#include <unistd.h>
#include <string.h>

int main(void) {
    const char *path = "/tmp/kf_fcntl_test.txt";
    int fd = open(path, O_CREAT | O_WRONLY | O_TRUNC, 0644);
    int flags = fcntl(fd, ____);
    printf("O_WRONLY set: %d\n", (flags & O_ACCMODE) == O_WRONLY);
    flags |= O_APPEND;
    fcntl(fd, ____, flags);
    int new_flags = fcntl(fd, F_GETFL);
    printf("O_APPEND set: %d\n", (new_flags & O_APPEND) != 0);
    int fdflags = fcntl(fd, ____);
    printf("FD_CLOEXEC: %d\n", (fdflags & FD_CLOEXEC) != 0);
    fcntl(fd, F_SETFD, fdflags | FD_CLOEXEC);
    fdflags = fcntl(fd, F_GETFD);
    printf("FD_CLOEXEC after set: %d\n", (fdflags & FD_CLOEXEC) != 0);
    close(fd);
    unlink(path);
    return 0;
